// Mute the video player
const video = document.querySelector('video');
if (video) {
  video.muted = true;
  video.volume = 0;
  'Muted video successfully';
} else {
  // Try the YouTube player element
  const player = document.querySelector('ytd-player');
  if (player) {
    player.mute();
    'Muted via player API';
  } else {
    'No video element found';
  }
}
